import{_ as e,o as a,c as n,a2 as p}from"./chunks/framework.C24VBsJ9.js";const m=JSON.parse('{"title":"存储介质基础","description":"","frontmatter":{"title":"存储介质基础"},"headers":[],"relativePath":"tutorial/flash/01_storage_media_basics.md","filePath":"tutorial/flash/01_storage_media_basics.md","lastUpdated":1781369075000}'),i={name:"tutorial/flash/01_storage_media_basics.md"};function d(l,s,t,c,o,r){return a(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="存储介质基础-先分清-sd、emmc-和块设备" tabindex="-1">存储介质基础 - 先分清 SD、eMMC 和块设备 <a class="header-anchor" href="#存储介质基础-先分清-sd、emmc-和块设备" aria-label="Permalink to &quot;存储介质基础 - 先分清 SD、eMMC 和块设备&quot;">​</a></h1><h2 id="前言-别急着烧-先认清-盘" tabindex="-1">前言：别急着烧，先认清“盘” <a class="header-anchor" href="#前言-别急着烧-先认清-盘" aria-label="Permalink to &quot;前言：别急着烧，先认清“盘”&quot;">​</a></h2><p>很多人第一次看到镜像烧录教程时，卡住的地方不是命令本身。</p><p>命令其实就那么几条：<code>lsblk</code>、<code>dd</code>、<code>sync</code>，或者 U-Boot 里的 <code>mmc list</code>、<code>mmc part</code>。但是我们有时候还是会难以理解烧录过程重出现的问题。</p><p>随意一些例子：</p><ul><li>SD 卡是什么？你很清楚这是一个存储设备</li><li>eMMC 又是什么？你很清楚这是一个存储设备，但是怎么正点原子或者一些厂商告诉你，你要用mfgtools了？怎么跟SD卡的不太一样？</li><li>/dev/sdb 和 /dev/sdb1 有什么区别？</li><li>U-Boot 里的 mmc 0 为什么到了 Linux 里又变成 /dev/mmcblk0？</li></ul><p>如果这些概念没分清楚，后面看到“把完整镜像写入整盘设备”这句话，就很容易只记住 <code>dd</code>，却不知道为什么 <code>of=</code> 不能写成分区。</p><p>所以这一章先不烧录。我们只做一件事：把板子上的存储介质和主机看到的块设备认清楚。</p><h2 id="sd-卡和-emmc-一个能拔-一个焊死" tabindex="-1">SD 卡和 eMMC：一个能拔，一个焊死 <a class="header-anchor" href="#sd-卡和-emmc-一个能拔-一个焊死" aria-label="Permalink to &quot;SD 卡和 eMMC：一个能拔，一个焊死&quot;">​</a></h2><p>在 IMX6ULL 这类板子上，最常见的两种启动存储是 SD 卡和 eMMC。</p><p>SD 卡大家比较熟。它是一张可以拔下来的卡。你可以把它插到读卡器里，主机就能像看到一个 U 盘一样看到它。烧录 SD 镜像时，主机直接对这张卡写数据。</p><p>eMMC 则不一样。它是一颗焊在板子上的存储芯片，外形上更像板子的一部分。你不能把 eMMC 拔下来插进电脑。想往 eMMC 里写镜像，通常要借助板子自己：让板子通过 USB 暂时把 eMMC 暴露给主机。这也就是我们说的UMS传递烧录。</p><p>后面讲 UUU + UMS 的时候，本质上就是在解决“eMMC 不能拔下来”这个问题。</p><h2 id="块设备是什么" tabindex="-1">块设备是什么 <a class="header-anchor" href="#块设备是什么" aria-label="Permalink to &quot;块设备是什么&quot;">​</a></h2><p>Linux 里把磁盘、U 盘、SD 卡、通过 UMS 暴露出来的 eMMC 这类东西，都看成块设备。</p><p>所谓块设备，可以简单理解成：一块可以按扇区读写的存储空间。它不像普通文件那样以“文件名”为第一视角，而是以“第几个字节、第几个扇区”为第一视角。</p><p>在主机上看块设备，最常用的是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你可能会看到这样的输出：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sdb      8:16   1  29.7G  0 disk</span></span>
<span class="line"><span>├─sdb1   8:17   1    64M  0 part</span></span>
<span class="line"><span>└─sdb2   8:18   1   512M  0 part</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这里先解释一下“分区”。一整块盘可以被切成几段相对独立的区域，每一段就叫一个分区。你可以把它想成一本厚笔记本：整本笔记本是 <code>sdb</code>，前面几十页专门放启动文件，后面几百页专门放根文件系统。每一段页码范围，就是一个分区。</p><p>Linux 不会只给整本笔记本起名字，它也会给每个分区起名字。所以 <code>lsblk</code> 里 <code>TYPE</code> 为 <code>disk</code> 的是整盘，<code>TYPE</code> 为 <code>part</code> 的就是分区。</p><p>这里 <code>sdb</code> 是整盘设备，<code>sdb1</code> 和 <code>sdb2</code> 是这块盘上的两个分区。</p><p>换成路径就是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/sdb   -&gt; 整张盘</span></span>
<span class="line"><span>/dev/sdb1  -&gt; 第 1 个分区</span></span>
<span class="line"><span>/dev/sdb2  -&gt; 第 2 个分区</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这不是名字长短的问题，而是层级不同。</p><h2 id="整盘设备和分区设备" tabindex="-1">整盘设备和分区设备 <a class="header-anchor" href="#整盘设备和分区设备" aria-label="Permalink to &quot;整盘设备和分区设备&quot;">​</a></h2><p>完整镜像必须写到整盘设备。这句话很重要，值得单独放一遍：完整镜像写整盘，不写分区。</p><p>为什么？</p><p>因为我们生成的 <code>.img</code> 不是一个“boot 分区文件系统”，也不是一个“rootfs 文件系统”。它是一整块盘的字节布局，里面已经包含：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>raw U-Boot 区域</span></span>
<span class="line"><span>MBR 分区表</span></span>
<span class="line"><span>boot 分区</span></span>
<span class="line"><span>rootfs 分区</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果你把它写到 <code>/dev/sdb</code>，意思是“从整张 SD 卡的第 0 字节开始，把整盘布局写进去”。这是对的。</p><p>如果你把它写到 <code>/dev/sdb1</code>，意思就变成“把整盘布局塞进第 1 个分区里面”。这样分区表会跑到分区内部，raw U-Boot 也不在 ROM Code 期待的位置，板子自然很难启动。</p><p>所以后面看到类似命令时：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=out/release-latest/images/imx6ull-aes-sd.img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=/dev/sdX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=4M</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>/dev/sdX</code> 代表的是例子里的整盘设备，不是 <code>/dev/sdX1</code>。</p><h2 id="为什么有时是-dev-sdx-有时是-dev-mmcblk0" tabindex="-1">为什么有时是 /dev/sdX，有时是 /dev/mmcblk0 <a class="header-anchor" href="#为什么有时是-dev-sdx-有时是-dev-mmcblk0" aria-label="Permalink to &quot;为什么有时是 /dev/sdX，有时是 /dev/mmcblk0&quot;">​</a></h2><p>主机上不同设备会有不同命名。</p><p>USB 读卡器、U 盘、通过 UMS 暴露出来的设备，常见名字是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/sdb</span></span>
<span class="line"><span>/dev/sdc</span></span>
<span class="line"><span>/dev/sdd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>它们的分区通常是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/sdb1</span></span>
<span class="line"><span>/dev/sdb2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>而板子自己运行 Linux 后，SD/eMMC 通常会叫：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/mmcblk0</span></span>
<span class="line"><span>/dev/mmcblk1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>对应分区会多一个 <code>p</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/mmcblk0p1</span></span>
<span class="line"><span>/dev/mmcblk0p2</span></span>
<span class="line"><span>/dev/mmcblk1p1</span></span>
<span class="line"><span>/dev/mmcblk1p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这里的 <code>p</code> 只是命名格式的一部分。它表示这是 <code>mmcblk0</code> 这个整盘设备上的第几个分区。</p><p>所以不要把 <code>/dev/sdb1</code> 和 <code>/dev/mmcblk0p1</code> 理解成两套不同规则。它们都在表达：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>整盘设备 + 分区编号</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>只是设备类型不一样，名字长得不一样。</p><h2 id="u-boot-的-mmc-0-1-和-linux-的-dev-mmcblk0-1" tabindex="-1">U-Boot 的 mmc 0/1 和 Linux 的 /dev/mmcblk0/1 <a class="header-anchor" href="#u-boot-的-mmc-0-1-和-linux-的-dev-mmcblk0-1" aria-label="Permalink to &quot;U-Boot 的 mmc 0/1 和 Linux 的 /dev/mmcblk0/1&quot;">​</a></h2><p>还有一个容易绕的地方：U-Boot 里的 <code>mmc 0</code>、<code>mmc 1</code>，和 Linux 里的 <code>/dev/mmcblk0</code>、<code>/dev/mmcblk1</code>，不是同一个命名系统。</p><p>U-Boot 在自己的驱动模型里给 MMC 设备编号。Linux 启动后，又由 Linux 内核按自己的枚举顺序创建设备名。</p><p>在当前 IMX-Forge 板卡约定里，我们使用这套映射：</p><table tabindex="0"><thead><tr><th>目标介质</th><th>U-Boot 里</th><th>Linux 里</th></tr></thead><tbody><tr><td>SD</td><td><code>mmc 0</code></td><td><code>/dev/mmcblk0p2</code></td></tr><tr><td>eMMC</td><td><code>mmc 1</code></td><td><code>/dev/mmcblk1p2</code></td></tr></tbody></table><p>这里的 <code>/dev/mmcblk0p2</code> 和 <code>/dev/mmcblk1p2</code> 指的是 rootfs 分区，也就是第 2 个分区。</p><p>不过这件事不要盲信。不同板子、不同 U-Boot 配置、不同接线，枚举顺序都可能变。教程后面会反复提醒：如果你不确定，先在 U-Boot 里看：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc list</span></span>
<span class="line"><span>mmc dev 0</span></span>
<span class="line"><span>mmc part</span></span>
<span class="line"><span>mmc dev 1</span></span>
<span class="line"><span>mmc part</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这些命令不会写存储，只是观察设备。</p><h2 id="在主机上怎么观察" tabindex="-1">在主机上怎么观察 <a class="header-anchor" href="#在主机上怎么观察" aria-label="Permalink to &quot;在主机上怎么观察&quot;">​</a></h2><p>主机侧最实用的办法是“前后对比”。</p><p>插入 SD 卡前看一次：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>插入 SD 卡后再看一次：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>新增出来的那块 <code>disk</code>，才是你的 SD 卡。</p><p>如果进入 UMS 前后对比，也一样：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>让板子进入 UMS 后再执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>新增出来的整盘设备，就是板子借给主机的 eMMC。</p><p>这里最怕的是凭记忆猜 <code>/dev/sdb</code>。今天它可能是 SD 卡，明天插了另一个 U 盘，它就可能变成 <code>/dev/sdc</code>。<code>dd</code> 不会替你判断对错，所以人要先判断。</p><h2 id="在-u-boot-里怎么观察" tabindex="-1">在 U-Boot 里怎么观察 <a class="header-anchor" href="#在-u-boot-里怎么观察" aria-label="Permalink to &quot;在 U-Boot 里怎么观察&quot;">​</a></h2><p>U-Boot 里常用这几条：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc list</span></span>
<span class="line"><span>mmc dev 0</span></span>
<span class="line"><span>mmc part</span></span>
<span class="line"><span>mmc dev 1</span></span>
<span class="line"><span>mmc part</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><code>mmc list</code> 看 U-Boot 当前识别到了哪些 MMC 设备。</p><p><code>mmc dev 0</code> 是选择第 0 个 MMC 设备。选择之后再 <code>mmc part</code>，就能看这个设备上有没有分区表。</p><p>如果你已经烧了镜像，还可以继续看文件：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ext4ls mmc 0:1 /</span></span>
<span class="line"><span>ext4ls mmc 0:2 /</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这里 <code>mmc 0:1</code> 的意思是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>U-Boot 的第 0 个 MMC 设备上的第 1 个分区</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这和 Linux 里的 <code>/dev/mmcblk0p1</code> 很像，但仍然要记住：它们是两个阶段里的两套名字。</p><h2 id="ums-是什么先有个印象" tabindex="-1">UMS 是什么先有个印象 <a class="header-anchor" href="#ums-是什么先有个印象" aria-label="Permalink to &quot;UMS 是什么先有个印象&quot;">​</a></h2><p>UMS 全称可以理解成 USB Mass Storage。这里不用先背术语，只要知道它做了什么：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>板子把自己的 eMMC 暂时伪装成一个 USB 存储设备，让主机来写。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也就是说，eMMC 本来焊在板子上，主机摸不到。进入 UMS 后，主机的 <code>lsblk</code> 会突然多出一块盘。你对这块新增的整盘设备写镜像，数据最终会落到板子的 eMMC 里。</p><p>后面的 eMMC 烧录章节会详细讲 UUU 怎么把 U-Boot 跑进 RAM，U-Boot 又怎么执行 <code>ums 0 mmc 1</code>。现在先知道这个目的就够了：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>UUU/UMS 不是另一种镜像格式，它只是让主机能够访问板上的 eMMC。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>这一章只讲了一个基础问题：镜像到底要写到哪里。</p><p>先把几个关键词收一下：</p><ul><li>SD 卡可以拔下来，用读卡器写。</li><li>eMMC 焊在板子上，通常通过 UUU/UMS 暴露给主机写。</li><li><code>/dev/sdX</code> 或 <code>/dev/mmcblk0</code> 是整盘设备。</li><li><code>/dev/sdX1</code> 或 <code>/dev/mmcblk0p1</code> 是分区设备。</li><li>完整 <code>.img</code> 要写整盘，不写分区。</li><li>U-Boot 的 <code>mmc 0/1</code> 和 Linux 的 <code>/dev/mmcblk0/1</code> 是两套命名，需要现场确认。</li></ul><p>下一章我们继续往下拆：既然 <code>.img</code> 是一整块盘，那它里面的分区表、boot 分区、rootfs 分区和普通文件到底是什么关系。</p><p><strong>下一步：</strong> 阅读 <a href="./02_image_partition_filesystem_basics">02_image_partition_filesystem_basics.md</a>，先把 <code>.img</code>、分区和文件系统这几个概念拆开。</p>`,94)])])}const h=e(i,[["render",d]]);export{m as __pageData,h as default};
